const TIPOS=[...new Set(PRODS.map(p=>p.tipo))];
const CATS=[...new Set(PRODS.map(p=>p.cat))];
const FAMS=[...new Set(PRODS.map(p=>p.fam))];
const PP=8;
const FOTOS=[FOTO1,FOTO2,FOTO3];

function Chip({tipo}){
  const s=TC[tipo]||{bg:G1,tx:G3,bo:G2};
  return <span style={{background:s.bg,color:s.tx,border:`1px solid ${s.bo}`,borderRadius:20,padding:"2px 9px",fontSize:11,fontWeight:700,whiteSpace:"nowrap"}}>{tipo}</span>;
}

function ModalContacto({tipo,onClose,onEnviar}){
  const [valor,setValor]=useState("");
  const label=tipo==="whatsapp"?"Número de WhatsApp":"Correo electrónico";
  const placeholder=tipo==="whatsapp"?"+34 600 000 000":"ejemplo@correo.com";
  return(
    <div onClick={onClose} style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:9999}}>
      <div onClick={e=>e.stopPropagation()} style={{background:BL,borderRadius:12,padding:"24px 26px",maxWidth:360,width:"90%",boxShadow:"0 8px 40px rgba(0,0,0,.3)"}}>
        <div style={{fontSize:13,fontWeight:800,color:TX,marginBottom:4}}>
          {tipo==="whatsapp"?"📱 Compartir por WhatsApp":"📧 Compartir por Email"}
        </div>
        <div style={{color:G3,fontSize:12,marginBottom:14}}>{label}:</div>
        <input value={valor} onChange={e=>setValor(e.target.value)} placeholder={placeholder}
          style={{width:"100%",padding:"8px 10px",borderRadius:7,border:`1px solid ${G2}`,fontSize:13,outline:"none",fontFamily:"inherit",boxSizing:"border-box",marginBottom:14}}/>
        <div style={{display:"flex",gap:8}}>
          <button onClick={onClose} style={{flex:1,padding:"8px",borderRadius:7,border:`1px solid ${G2}`,background:BL,color:G3,fontWeight:600,fontSize:12,cursor:"pointer"}}>Cancelar</button>
          <button onClick={()=>{onEnviar(valor);onClose();}} disabled={!valor.trim()}
            style={{flex:2,padding:"8px",borderRadius:7,border:"none",background:valor.trim()?V:G2,color:BL,fontWeight:700,fontSize:12,cursor:valor.trim()?"pointer":"not-allowed"}}>
            {tipo==="whatsapp"?"Enviar por WhatsApp":"Enviar por Email"}
          </button>
        </div>
      </div>
    </div>
  );
}

function ModalProducto({prod,onClose,onSelect,seleccionados}){
  if(!prod)return null;
  const yaEsta=seleccionados.some(s=>s.id===prod.id);
  return(
    <div onClick={onClose} style={{position:"fixed",inset:0,background:"rgba(0,0,0,.5)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:9998}}>
      <div onClick={e=>e.stopPropagation()} style={{background:BL,borderRadius:14,padding:"26px 28px",maxWidth:440,width:"92%",boxShadow:"0 8px 40px rgba(0,0,0,.3)"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:16}}>
          <div>
            <div style={{fontSize:10,color:G3,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:3}}>Detalle de Oferta</div>
            <div style={{fontSize:14,fontWeight:800,color:TX,lineHeight:1.3,maxWidth:320}}>{prod.desc}</div>
          </div>
          <button onClick={onClose} style={{background:"none",border:"none",fontSize:20,cursor:"pointer",color:G3,paddingLeft:10}}>✕</button>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:9,marginBottom:16}}>
          {[
            {l:"Categoría",      v:prod.cat},
            {l:"Subfamilia",     v:prod.fam},
            {l:"Tipo oferta",    v:<Chip tipo={prod.tipo}/>},
            {l:"Vigencia",       v:`${prod.fi} → ${prod.ff}`},
            {l:"Precio oferta",  v:prod.pvp?`€ ${prod.pvp.toFixed(2)}`:"Ver en tienda", c:prod.pvp?RJ:G3},
            {l:"Precio anterior",v:prod.ant?`€ ${prod.ant.toFixed(2)}`:"—", c:G3},
          ].map(f=>(
            <div key={f.l} style={{background:G1,borderRadius:7,padding:"8px 10px"}}>
              <div style={{fontSize:10,color:G3,fontWeight:600,textTransform:"uppercase",letterSpacing:"0.05em",marginBottom:3}}>{f.l}</div>
              <div style={{fontSize:12,fontWeight:700,color:f.c||TX}}>{f.v}</div>
            </div>
          ))}
        </div>
        <div style={{display:"flex",gap:8}}>
          <button onClick={onClose} style={{flex:1,padding:"9px",borderRadius:7,border:`1px solid ${G2}`,background:BL,color:G3,fontWeight:600,fontSize:13,cursor:"pointer"}}>Cerrar</button>
          <button onClick={()=>{onSelect(prod);onClose();}} style={{flex:2,padding:"9px",borderRadius:7,border:"none",background:yaEsta?"#E65100":V,color:BL,fontWeight:700,fontSize:13,cursor:"pointer"}}>
            {yaEsta?"✓ Ya en mi selección":"+ Agregar a Mi Selección"}
          </button>
        </div>
      </div>
    </div>
  );
}

function Header({vista,setVista,seleccionados}){
  return(
    <header style={{background:V,boxShadow:"0 2px 10px rgba(0,80,30,.3)",position:"sticky",top:0,zIndex:100}}>
      <div style={{display:"flex",alignItems:"center",padding:"0 28px",height:64,position:"relative"}}>
        {/* Logo + nombre — izquierda */}
        <div style={{display:"flex",alignItems:"center",gap:10,cursor:"pointer",zIndex:1}} onClick={()=>setVista("bienvenida")}>
          <img src={LOGO} alt="logo" style={{height:42,width:42,borderRadius:"50%",objectFit:"cover",background:BL}}/>
          <div style={{color:BL,fontWeight:900,fontSize:16,fontFamily:"Georgia,serif"}}>Carrefour <span style={{fontStyle:"italic",fontWeight:400}}>express</span></div>
        </div>
        {/* OFERTAS — centrado absoluto */}
        <div style={{position:"absolute",left:0,right:0,display:"flex",justifyContent:"center",pointerEvents:"none"}}>
          <span style={{color:BL,fontWeight:900,fontSize:22,fontFamily:"Georgia,serif",letterSpacing:"0.06em"}}>Ofertas</span>
        </div>
        {/* Botones — derecha */}
        <div style={{display:"flex",alignItems:"center",gap:6,marginLeft:"auto",zIndex:1}}>
          {vista==="bienvenida"&&(
            <>
              <button style={{padding:"5px 13px",borderRadius:6,fontSize:12,fontWeight:600,cursor:"pointer",border:"1px solid rgba(255,255,255,.5)",background:"transparent",color:BL}}>Sign Up</button>
              <button style={{padding:"5px 13px",borderRadius:6,fontSize:12,fontWeight:600,cursor:"pointer",border:"1px solid rgba(255,255,255,.5)",background:"transparent",color:BL}}>Login</button>
            </>
          )}
          {(vista==="campana"||vista==="seleccion")&&(
            <button onClick={()=>setVista("bienvenida")} style={{padding:"5px 13px",borderRadius:6,fontSize:12,fontWeight:600,cursor:"pointer",border:"1px solid rgba(255,255,255,.4)",background:"transparent",color:"rgba(255,255,255,.75)"}}>Logoff</button>
          )}
        </div>
      </div>
      {(vista==="campana"||vista==="seleccion")&&(
        <div style={{background:V2,padding:"0 20px",display:"flex",gap:1}}>
          <button onClick={()=>setVista("campana")} style={{padding:"7px 16px",fontSize:12,fontWeight:600,cursor:"pointer",border:"none",borderBottom:vista==="campana"?`3px solid ${AM}`:"3px solid transparent",background:"transparent",color:vista==="campana"?AM:BL,whiteSpace:"nowrap",borderRadius:"4px 4px 0 0"}}>
            Campaña Actual
          </button>
          <button onClick={()=>setVista("seleccion")} style={{padding:"7px 16px",fontSize:12,fontWeight:600,cursor:"pointer",border:"none",borderBottom:vista==="seleccion"?`3px solid ${AM}`:"3px solid transparent",background:"transparent",color:vista==="seleccion"?AM:BL,whiteSpace:"nowrap",borderRadius:"4px 4px 0 0",display:"flex",alignItems:"center",gap:5}}>
            Mi Selección
            {seleccionados.length>0&&<span style={{background:AM,color:V2,borderRadius:"50%",width:18,height:18,fontSize:10,fontWeight:800,display:"inline-flex",alignItems:"center",justifyContent:"center"}}>{seleccionados.length}</span>}
          </button>
        </div>
      )}
    </header>
  );
}

