function Bienvenida({setVista}){
  const [foto,setFoto]=useState(0);
  useEffect(()=>{
    const t=setInterval(()=>setFoto(f=>(f+1)%3),3500);
    return()=>clearInterval(t);
  },[]);
  return(
    <div style={{display:"flex",flexDirection:"column"}}>
      {/* Slideshow altura fija — todas las fotos llenan el mismo espacio */}
      <div style={{position:"relative",height:580,overflow:"hidden",background:"#1a4a2a",flexShrink:0}}>
        {[
          {src:FOTO1, pos:"center center", scale:"scale(1)"},
          {src:FOTO2, pos:"top center",    scale:"scale(1)"},
          {src:FOTO3, pos:"center center", scale:"scale(1.25)"},
        ].map((f,i)=>(
          <img key={i} src={f.src} alt="" style={{
            position:"absolute",top:0,left:0,
            width:"100%",height:"100%",
            objectFit:"cover",objectPosition:f.pos,
            transform:f.scale,
            opacity:foto===i?1:0,
            transition:"opacity 1s ease",
          }}/>
        ))}
        {/* Overlay verde */}
        <div style={{position:"absolute",inset:0,background:"rgba(0,90,40,.48)",zIndex:2}}/>
        {/* Contenido centrado */}
        <div style={{position:"absolute",inset:0,display:"flex",flexDirection:"column",
          alignItems:"center",justifyContent:"center",padding:"0 24px",textAlign:"center",zIndex:3}}>
          <img src={LOGO} alt="logo" style={{height:180,width:180,borderRadius:"50%",
            objectFit:"cover",background:BL,marginBottom:22,
            boxShadow:"0 4px 20px rgba(0,0,0,.4)"}}/>
          <h1 style={{color:BL,fontSize:39,fontWeight:900,fontFamily:"Georgia,serif",
            lineHeight:1.2,marginBottom:20,textShadow:"0 2px 8px rgba(0,0,0,.4)",
            maxWidth:750}}>
            Las Ofertas de su Proveedor de Conveniencia Preferido
          </h1>
          <p style={{color:"rgba(255,255,255,.9)",fontSize:22,fontWeight:500,
            textShadow:"0 1px 4px rgba(0,0,0,.4)",maxWidth:620}}>
            Los productos que Ud. necesita donde Ud. los necesita cuando Ud. los necesita
          </p>
        </div>
        {/* Indicadores slideshow */}
        <div style={{position:"absolute",bottom:16,left:0,right:0,
          display:"flex",justifyContent:"center",gap:8,zIndex:4}}>
          {FOTOS.map((_,i)=>(
            <button key={i} onClick={()=>setFoto(i)} style={{
              width:foto===i?24:8,height:8,borderRadius:4,border:"none",
              background:foto===i?AM:"rgba(255,255,255,.5)",
              cursor:"pointer",transition:"all .3s",padding:0}}/>
          ))}
        </div>
      </div>
      {/* Franja Ver Ofertas — entre fotos y footer, sin espacio blanco */}
      <div style={{background:V,padding:"22px 24px",textAlign:"center",lineHeight:1}}>
        <button onClick={()=>setVista("campana")} style={{
          padding:"14px 40px",borderRadius:9,border:"none",
          background:AM,color:V2,fontWeight:800,fontSize:16,
          cursor:"pointer",boxShadow:"0 4px 16px rgba(0,0,0,.2)"}}>
          Ver Ofertas
        </button>
      </div>
    </div>
  );
}

function CampanaActual({seleccionados,setSeleccionados}){
  const [fil,setFil]=useState("TODOS");
  const [busq,setBusq]=useState("");
  const [pag,setPag]=useState(1);
  const [modal,setModal]=useState(null);

  const filt=PRODS.filter(p=>{
    const mf=fil==="TODOS"||p.tipo===fil;
    const mb=!busq||
      p.desc.toLowerCase().includes(busq.toLowerCase())||
      p.cat.toLowerCase().includes(busq.toLowerCase())||
      p.fam.toLowerCase().includes(busq.toLowerCase());
    return mf&&mb;
  });
  const tP=Math.ceil(filt.length/PP)||1;
  const pg=filt.slice((pag-1)*PP,pag*PP);

  const toggleSel=(prod)=>{
    setSeleccionados(s=>s.some(x=>x.id===prod.id)
      ?s.filter(x=>x.id!==prod.id)
      :[...s,{...prod,cantidad:1}]);
  };

  return(
    <div>
      <ModalProducto prod={modal} onClose={()=>setModal(null)} onSelect={toggleSel} seleccionados={seleccionados}/>

      {/* Línea 1: Info campaña + stats */}
      <div style={{background:BL,borderRadius:9,padding:"10px 16px",border:`1px solid ${G2}`,marginBottom:8,display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8}}>
        <div>
          <span style={{fontWeight:800,color:V2,fontSize:13}}>1ª Quincena Marzo 2026</span>
          <span style={{color:G3,fontSize:12,marginLeft:8}}>· Válida del 25 feb al 11 mar</span>
          <span style={{background:V3,color:V,border:`1px solid ${V}`,borderRadius:20,padding:"1px 10px",fontSize:11,fontWeight:700,marginLeft:10}}>✓ VIGENTE</span>
        </div>
        <div style={{display:"flex",gap:8,flexWrap:"wrap",alignItems:"center"}}>
          <span style={{fontSize:11,color:G3}}><b style={{color:V}}>{PRODS.length}</b> productos</span>
          <span style={{color:G2}}>·</span>
          <span style={{fontSize:11,color:G3}}><b style={{color:V}}>{CATS.length}</b> categorías</span>
          <span style={{color:G2}}>·</span>
          <span style={{fontSize:11,color:G3}}><b style={{color:V}}>{FAMS.length}</b> subfamilias</span>
        </div>
      </div>

      {/* Línea 2: Búsqueda + filtros por tipo */}
      <div style={{background:BL,borderRadius:9,padding:"10px 14px",border:`1px solid ${G2}`,marginBottom:10,display:"flex",gap:8,flexWrap:"wrap",alignItems:"center"}}>
        <input
          placeholder="🔍 Buscar por descripción, categoría o subfamilia..."
          value={busq}
          onChange={e=>{setBusq(e.target.value);setPag(1);}}
          style={{flex:1,minWidth:200,padding:"6px 10px",borderRadius:7,border:`1px solid ${G2}`,fontSize:12,outline:"none",fontFamily:"inherit"}}
        />
        <div style={{display:"flex",gap:4,flexWrap:"wrap"}}>
          <button onClick={()=>{setFil("TODOS");setPag(1);}} style={{padding:"3px 10px",borderRadius:20,fontSize:11,fontWeight:600,cursor:"pointer",border:fil==="TODOS"?"none":`1px solid ${G2}`,background:fil==="TODOS"?V:BL,color:fil==="TODOS"?BL:G3}}>Todos</button>
          {TIPOS.map(t=>(
            <button key={t} onClick={()=>{setFil(t);setPag(1);}} style={{padding:"3px 10px",borderRadius:20,fontSize:11,fontWeight:600,cursor:"pointer",border:fil===t?"none":`1px solid ${G2}`,background:fil===t?V:BL,color:fil===t?BL:G3,whiteSpace:"nowrap"}}>{t}</button>
          ))}
        </div>
      </div>

      {/* Tabla */}
      <div style={{background:BL,borderRadius:8,border:`1px solid ${G2}`,overflow:"hidden"}}>
        <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
          <thead>
            <tr style={{background:V2,color:BL}}>
              {["Categoría","Descripción / Subfamilia","Oferta","Precio","Ant.","Vigencia",""].map(h=>(
                <th key={h} style={{padding:"9px 10px",textAlign:"left",fontSize:11,fontWeight:700,letterSpacing:"0.04em",whiteSpace:"nowrap"}}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {pg.map((p,i)=>{
              const yaEsta=seleccionados.some(s=>s.id===p.id);
              return(
                <tr key={p.id} style={{background:yaEsta?V3:i%2===0?BL:G1,borderBottom:`1px solid ${G2}`}}>
                  <td style={{padding:"7px 10px",color:G3,fontSize:11,whiteSpace:"nowrap"}}>{p.cat}</td>
                  <td style={{padding:"7px 10px",maxWidth:200}}>
                    <div style={{fontWeight:600,color:TX,lineHeight:1.3}}>{p.desc}</div>
                    <div style={{color:G3,fontSize:10,marginTop:1}}>{p.fam}</div>
                  </td>
                  <td style={{padding:"7px 10px"}}><Chip tipo={p.tipo}/></td>
                  <td style={{padding:"7px 10px",fontWeight:800,color:RJ,whiteSpace:"nowrap",fontSize:13}}>
                    {p.pvp?`€ ${p.pvp.toFixed(2)}`:"—"}
                  </td>
                  <td style={{padding:"7px 10px",whiteSpace:"nowrap"}}>
                    {p.ant?<span style={{color:G3,fontSize:11,textDecoration:"line-through"}}>€ {p.ant.toFixed(2)}</span>:"—"}
                  </td>
                  <td style={{padding:"7px 10px",color:G3,fontSize:11,whiteSpace:"nowrap"}}>
                    <div>{p.fi}</div><div style={{color:G2}}>→ {p.ff}</div>
                  </td>
                  <td style={{padding:"7px 10px",whiteSpace:"nowrap"}}>
                    <div style={{display:"flex",gap:4}}>
                      <button onClick={()=>setModal(p)} style={{background:G1,color:G3,border:`1px solid ${G2}`,borderRadius:5,padding:"3px 7px",fontSize:11,fontWeight:600,cursor:"pointer"}}>Ver</button>
                      <button onClick={()=>toggleSel(p)} style={{background:yaEsta?V3:V,color:yaEsta?V:BL,border:`1px solid ${V}`,borderRadius:5,padding:"3px 8px",fontSize:11,fontWeight:700,cursor:"pointer",whiteSpace:"nowrap"}}>
                        {yaEsta?"✓":"+ Selec."}
                      </button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        <div style={{padding:"8px 12px",borderTop:`1px solid ${G2}`,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <span style={{color:G3,fontSize:11}}>{filt.length===0?"Sin resultados":`${(pag-1)*PP+1}–${Math.min(pag*PP,filt.length)} de ${filt.length} ofertas`}</span>
          <div style={{display:"flex",gap:3}}>
            <button onClick={()=>setPag(p=>Math.max(1,p-1))} disabled={pag===1} style={{padding:"3px 8px",borderRadius:4,border:`1px solid ${G2}`,fontSize:11,background:pag===1?G1:BL,color:pag===1?G2:V,fontWeight:600,cursor:pag===1?"default":"pointer"}}>←</button>
            {Array.from({length:Math.min(5,tP)},(_,i)=>{const n=Math.max(1,Math.min(pag-2,tP-4))+i;return <button key={n} onClick={()=>setPag(n)} style={{padding:"3px 7px",borderRadius:4,fontSize:11,fontWeight:600,cursor:"pointer",border:pag===n?"none":`1px solid ${G2}`,background:pag===n?V:BL,color:pag===n?BL:V}}>{n}</button>;})}
            <button onClick={()=>setPag(p=>Math.min(tP,p+1))} disabled={pag===tP} style={{padding:"3px 8px",borderRadius:4,border:`1px solid ${G2}`,fontSize:11,background:pag===tP?G1:BL,color:pag===tP?G2:V,fontWeight:600,cursor:pag===tP?"default":"pointer"}}>→</button>
          </div>
        </div>
      </div>
    </div>
  );
}

function MiSeleccion({seleccionados,setSeleccionados}){
  const [modalContacto,setModalContacto]=useState(null);

  const actualizar=(id,cant)=>{if(cant<1)return;setSeleccionados(s=>s.map(p=>p.id===id?{...p,cantidad:cant}:p));};
  const eliminar=(id)=>setSeleccionados(s=>s.filter(p=>p.id!==id));
  const limpiar=()=>setSeleccionados([]);

  const textoLista=()=>"📋 *Mis ofertas Carrefour Express*\n\n"+
    seleccionados.map(p=>`• ${p.desc} (x${p.cantidad})${p.pvp?" — €"+p.pvp.toFixed(2)+" c/u":""}`).join("\n")+
    "\n\n_Campaña vigente del 25 feb al 11 mar_";

  const enviarWA=(tel)=>{
    const num=tel.replace(/\D/g,"");
    window.open(`https://wa.me/${num}?text=${encodeURIComponent(textoLista())}`,"_blank");
  };
  const enviarEmail=(email)=>{
    window.open(`mailto:${email}?subject=Mis%20ofertas%20Carrefour%20Express&body=${encodeURIComponent(textoLista())}`);
  };

  if(seleccionados.length===0) return(
    <div style={{textAlign:"center",padding:"52px 20px"}}>
      <div style={{fontSize:52,marginBottom:12}}>📋</div>
      <h2 style={{fontSize:18,fontWeight:800,color:V2,marginBottom:6}}>Tu lista de ofertas está vacía</h2>
      <p style={{color:G3,fontSize:13}}>Explorá las ofertas y presioná <b>+ Selec.</b> para agregar productos a tu lista.</p>
    </div>
  );

  return(
    <div>
      {modalContacto&&(
        <ModalContacto
          tipo={modalContacto}
          onClose={()=>setModalContacto(null)}
          onEnviar={modalContacto==="whatsapp"?enviarWA:enviarEmail}
        />
      )}
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14,flexWrap:"wrap",gap:8}}>
        <div>
          <h2 style={{fontSize:18,fontWeight:800,color:V2,margin:0}}>📋 Mi Selección</h2>
          <div style={{color:G3,fontSize:12,marginTop:2}}>{seleccionados.length} producto{seleccionados.length!==1?"s":""} seleccionado{seleccionados.length!==1?"s":""}</div>
        </div>
        <div style={{display:"flex",gap:7,flexWrap:"wrap"}}>
          <button onClick={()=>setModalContacto("whatsapp")}
            style={{padding:"7px 14px",borderRadius:7,border:"none",background:"#25D366",color:BL,fontWeight:700,fontSize:12,cursor:"pointer"}}>
            📱 WhatsApp
          </button>
          <button onClick={()=>setModalContacto("email")}
            style={{padding:"7px 14px",borderRadius:7,border:"none",background:"#1A73E8",color:BL,fontWeight:700,fontSize:12,cursor:"pointer"}}>
            📧 Email
          </button>
          <button onClick={()=>window.print()}
            style={{padding:"7px 14px",borderRadius:7,border:`1px solid ${G2}`,background:BL,color:G3,fontWeight:600,fontSize:12,cursor:"pointer"}}>
            🖨️ Imprimir
          </button>
          <button onClick={limpiar}
            style={{padding:"7px 14px",borderRadius:7,border:`1px solid ${RJ}`,background:BL,color:RJ,fontWeight:600,fontSize:12,cursor:"pointer"}}>
            🗑️ Limpiar
          </button>
        </div>
      </div>

      <div style={{background:BL,borderRadius:9,border:`1px solid ${G2}`,overflow:"hidden"}}>
        <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
          <thead>
            <tr style={{background:V2,color:BL}}>
              {["Categoría","Descripción","Oferta","Precio","Cantidad","Total",""].map(h=>(
                <th key={h} style={{padding:"9px 10px",textAlign:"left",fontSize:11,fontWeight:700,whiteSpace:"nowrap"}}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {seleccionados.map((p,i)=>(
              <tr key={p.id} style={{background:i%2===0?BL:G1,borderBottom:`1px solid ${G2}`}}>
                <td style={{padding:"8px 10px",color:G3,fontSize:11,whiteSpace:"nowrap"}}>{p.cat}</td>
                <td style={{padding:"8px 10px",maxWidth:200}}>
                  <div style={{fontWeight:600,color:TX,lineHeight:1.3}}>{p.desc}</div>
                  <div style={{color:G3,fontSize:10,marginTop:1}}>{p.fam}</div>
                </td>
                <td style={{padding:"8px 10px"}}><Chip tipo={p.tipo}/></td>
                <td style={{padding:"8px 10px",fontWeight:800,color:RJ,whiteSpace:"nowrap"}}>{p.pvp?`€ ${p.pvp.toFixed(2)}`:"—"}</td>
                <td style={{padding:"8px 10px"}}>
                  <div style={{display:"flex",alignItems:"center",gap:4}}>
                    <button onClick={()=>actualizar(p.id,p.cantidad-1)} style={{width:24,height:24,borderRadius:4,border:`1px solid ${G2}`,background:BL,color:V,fontWeight:800,fontSize:14,cursor:"pointer",lineHeight:1}}>−</button>
                    <span style={{minWidth:24,textAlign:"center",fontWeight:700,color:TX}}>{p.cantidad}</span>
                    <button onClick={()=>actualizar(p.id,p.cantidad+1)} style={{width:24,height:24,borderRadius:4,border:`1px solid ${G2}`,background:BL,color:V,fontWeight:800,fontSize:14,cursor:"pointer",lineHeight:1}}>+</button>
                  </div>
                </td>
                <td style={{padding:"8px 10px",fontWeight:700,color:TX,whiteSpace:"nowrap"}}>{p.pvp?`€ ${(p.pvp*p.cantidad).toFixed(2)}`:"—"}</td>
                <td style={{padding:"8px 10px"}}>
                  <button onClick={()=>eliminar(p.id)} style={{background:"none",border:"none",color:RJ,fontSize:16,cursor:"pointer",padding:"0 4px"}}>✕</button>
                </td>
              </tr>
            ))}
          </tbody>
          <tfoot>
            <tr style={{background:V3,borderTop:`2px solid ${V}`}}>
              <td colSpan={5} style={{padding:"10px",fontWeight:800,color:V2,fontSize:13,textAlign:"right"}}>Total estimado:</td>
              <td style={{padding:"10px",fontWeight:800,color:RJ,fontSize:14,whiteSpace:"nowrap"}}>
                {seleccionados.some(p=>p.pvp)?`€ ${seleccionados.filter(p=>p.pvp).reduce((a,p)=>a+(p.pvp*p.cantidad),0).toFixed(2)}`:"—"}
              </td>
              <td></td>
            </tr>
          </tfoot>
        </table>
      </div>
      <div style={{marginTop:8,color:G3,fontSize:11,textAlign:"right"}}>* Solo se suman productos con precio visible.</div>
    </div>
  );
}

export default function CarrefourUsers(){
  const [vista,setVista]=useState("bienvenida");
  const [seleccionados,setSeleccionados]=useState([]);
  return(
    <div style={{minHeight:"100vh",background:G1,fontFamily:"Segoe UI,Arial,sans-serif",display:"flex",flexDirection:"column"}}>
      <Header vista={vista} setVista={setVista} seleccionados={seleccionados}/>
      <main style={{flex:1,display:"flex",flexDirection:"column"}}>
        {vista==="bienvenida"&&<Bienvenida setVista={setVista}/>}
        {(vista==="campana"||vista==="seleccion")&&(
          <div style={{maxWidth:1040,margin:"0 auto",width:"100%",padding:"18px 14px"}}>
            {vista==="campana"&&(
              <div>
                <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12,flexWrap:"wrap",gap:8}}>
                  <h1 style={{fontSize:18,fontWeight:800,color:V2,margin:0}}>🏷️ Campaña Actual</h1>
                </div>
                <CampanaActual seleccionados={seleccionados} setSeleccionados={setSeleccionados}/>
              </div>
            )}
            {vista==="seleccion"&&<MiSeleccion seleccionados={seleccionados} setSeleccionados={setSeleccionados}/>}
          </div>
        )}
      </main>
      <Footer/>
    </div>
  );
}
